// ── Parse RapidAPI Yahoo Finance response ─────────────────────
// yahoo-finance15 returns either quoteResponse.result or body[]
const raw = $('Yahoo Finance').first().json;
const quotes = raw.quoteResponse?.result
            || raw.body
            || (Array.isArray(raw) ? raw : []);

const yf = {};
quotes.forEach(q => {
  const sym = q.symbol || q.ticker || '';
  const price = q.regularMarketPrice?.raw
              ?? q.regularMarketPrice
              ?? q.price?.regularMarketPrice?.raw
              ?? 0;
  if (sym) yf[sym] = Number(price) || 0;
});

const ethData = $('CoinGecko ETH').first().json;
const usdsgd = yf['USDSGD=X'] || 1.35;
const ethSGD  = Number(ethData?.ethereum?.sgd) || 2700;

const S  = v => (v==null||isNaN(v)||!isFinite(v)) ? 0 : Number(v);
const f0 = v => S(v).toFixed(0);
const f1 = v => S(v).toFixed(1);
const f4 = v => S(v).toFixed(4);

const pos = [
  {sym:'AJBU.SI', n:'KepDC', qty:500,    cost:1.9562,  c:'SGD'},
  {sym:'C38U.SI', n:'CICT',  qty:500,    cost:1.9842,  c:'SGD'},
  {sym:'HYDD.SI', n:'BYD',   qty:1600,   cost:1.9794,  c:'SGD'},
  {sym:'J69U.SI', n:'FCT',   qty:800,    cost:2.1579,  c:'SGD'},
  {sym:'JYEU.SI', n:'JYEU',  qty:900,    cost:0.595,   c:'SGD'},
  {sym:'NVDA',    n:'NVDA',  qty:3,      cost:173.99,  c:'USD'},
  {sym:'O5RU.SI', n:'AIMS',  qty:500,    cost:1.2775,  c:'SGD'},
  {sym:'TSLA',    n:'TSLA',  qty:0.3549, cost:318.683, c:'USD'}
];

let totVal=0, totPL=0;
const rows=[];
for (const p of pos) {
  const raw=S(yf[p.sym]);
  const pr=S(p.c==='USD'?raw*usdsgd:raw);
  const co=S(p.c==='USD'?p.cost*usdsgd:p.cost);
  const val=S(p.qty*pr), cst=S(p.qty*co), pl=S(val-cst);
  const pct=cst>0?S(pl/cst*100):0;
  totVal+=val; totPL+=pl;
  rows.push({n:p.n, raw, val, pl, pct, noP:!raw});
}

const eV=S(0.38935156*ethSGD), ePL=S(eV-0.38935156*2560), ePct=S((ethSGD-2560)/2560*100);
const bV=S(1.1624*100.16*usdsgd), bPL=S(bV-1.1624*108.40*usdsgd), bPct=S((100.16-108.40)/108.40*100);
const fV=S(95.6727*1.226);
totVal+=eV+bV+fV; totPL+=ePL+bPL+S(fV-117);

const al=[];
rows.forEach(r=>{ if(r.pct<=-10&&!r.noP) al.push(r.n+' '+f1(r.pct)+'%'); });
if(ePct<=-15) al.push('ETH '+f1(ePct)+'%');
const byd=rows.find(r=>r.n==='BYD');
if(byd&&totVal>0&&byd.val/totVal*100>25) al.push('BYD '+f1(byd.val/totVal*100)+'% of port!');
const noPriceList=rows.filter(r=>r.noP).map(r=>r.n);
if(noPriceList.length) al.push('No price: '+noPriceList.join(','));

const t=new Date().toLocaleString('en-SG',{timeZone:'Asia/Singapore',
  day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'});
const em=totPL>=0?'UP':'DN';
const sg=totPL>=0?'+':'';

// MSG1 — summary
const alertLine = al.length ? 'ALERTS: '+al.join(' | ') : 'All clear';
const msg1 = [
  '['+em+'] Bobby Portfolio '+t,
  'Total: S$'+Math.round(totVal).toLocaleString()+' | P/L: '+sg+'S$'+Math.round(totPL),
  'FX: '+f4(usdsgd)+' | ETH: S$'+f0(ethSGD),
  alertLine
].join('\n').substring(0,400);

// MSG2 — positions (pairs per line)
const pLines=[];
for(let i=0;i<rows.length;i+=2){
  const a=rows[i], b=rows[i+1];
  pLines.push(
    a.n+' '+(a.pl>=0?'+':'')+f1(a.pct)+'%'+
    (b?' | '+b.n+' '+(b.pl>=0?'+':'')+f1(b.pct)+'%':'')
  );
}
pLines.push('ETH '+(ePL>=0?'+':'')+f1(ePct)+'% | BGF '+(bPL>=0?'+':'')+f1(bPct)+'%');
pLines.push('Fullerton S$'+f0(fV)+' (stable)');
const msg2 = ('Positions:\n'+pLines.join('\n')).substring(0,400);

// Debug: show raw price keys received
const priceKeys = Object.keys(yf).join(',');

return [{json:{
  msg1, msg2,
  msg1_length: msg1.length,
  msg2_length: msg2.length,
  prices_received: Object.keys(yf).length,
  price_keys: priceKeys,
  total_value: Math.round(totVal*100)/100,
  total_pl:    Math.round(totPL*100)/100,
  usdsgd:      Math.round(usdsgd*10000)/10000,
  eth_sgd:     ethSGD,
  alert_count: al.length,
  timestamp:   new Date().toISOString()
}}];
